// Auto-generated from sam_lua_runtime.cpp / sam_js_runtime.cpp — the SAM scripting API surface.
// Powers the in-tool API reference, event catalog, and script-editor autocomplete.
//
// The API is registered identically in the Lua and QuickJS (JS/TS) runtimes. In the shipped
// (engine) build every function below exists in all three languages. Argument order/types and
// return values were read from the C implementations (lua_sam_* / js_sam_*), not guessed.
//
// hostOnly === true means the call mutates or reads authoritative game state and is refused on
// a multiplayer CLIENT (or is otherwise host/singleplayer-only per the framework docs); a
// refused call is a logged no-op, never a crash.
//
// Shared constant sets referenced by `values` below:
//   PLAYER_STATS  — sam_get_stat / sam_set_stat
//   MONSTER_STATS — sam_get_monster_stat / sam_set_monster_stat (no GOLD/EXP; DEX aliases SPEED)
//   EFFECTS       — sam_apply_effect / sam_remove_effect / sam_has_effect / *_monster_effect
//   EQUIP_SLOTS   — sam_get_equipped_item

export const PLAYER_STATS = ["STR", "DEX", "CON", "INT", "PER", "CHR", "HP", "MAXHP", "MP", "MAXMP", "GOLD", "LEVEL", "LVL", "EXP"];
export const MONSTER_STATS = ["STR", "DEX", "SPEED", "CON", "INT", "PER", "CHR", "HP", "MAXHP", "MP", "MAXMP", "LEVEL", "LVL"];
export const EFFECTS = ["LEVITATING", "INVISIBLE", "CONFUSED", "POISONED", "BLEEDING", "ASLEEP", "PARALYZED", "DRUNK", "BLIND", "GREASY", "VOMITING", "WEBBED", "SLOW", "FAST"];
export const EQUIP_SLOTS = ["WEAPON", "SHIELD", "HELMET", "ARMOR", "BREASTPLATE", "GLOVES", "BOOTS", "SHOES", "RING", "AMULET", "CLOAK", "MASK"];

/**
 * Barony's own bound action names, as a script sees them. Reacting to one of these
 * follows whatever the player rebound it to — that's why you use these instead of a
 * raw key, and why a mod can't collide with someone's keybinds.
 * Defaults for reference: Attack=Mouse1, Use=Mouse3, Defend=Space, Cast Spell=F,
 * "Hotbar Up / Select"=Mouse2 (right-click). Names are space/case-sensitive.
 */
export const ACTIONS = [
  "Attack", "Defend", "Use", "Cast Spell", "Sneak",
  "Hotbar Up / Select", "Hotbar Down / Cancel", "Hotbar Left", "Hotbar Right",
  "Call Out", "Command NPC", "Quick Turn",
];

